class SavingsGoal:
    def __init__(self, name, target):
        self.name = name
        self.target = max(1, target)
        self.saved = 0

    def deposit(self, amount):
        if amount > 0:
            self.saved += amount
        return self.saved

    def percent_complete(self):
        return int((self.saved / self.target) * 100)

    def summary(self):
        return f"{self.name}: {self.percent_complete()}% complete"

